using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

std::string getDllPath();

Ptr CreateBox()
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr centerPoint = Point3D::create(0.0, 10.0, 0.0);
    Ptr lengthDir = Vector3D::create(1.0, 0.0, 0.0);
    Ptr widthDir = Vector3D::create(0.0, 1.0, 0.0);

    Ptr orientedBoundingBox3D =
        OrientedBoundingBox3D::create(centerPoint, lengthDir, widthDir, 5.0, 6.0, 2.0);

    // Create box
    Ptr box = tempBRepMgr->createBox(orientedBoundingBox3D);

    return box;
}

Ptr CreateCylinderOrCone(double radius1, double radius2)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr point1 = Point3D::create(3.0, 3.0, 3.0);
    Ptr point2 = Point3D::create(-3.0, -3.0, -3.0);

    // Create Cylinder Or Cone
    Ptr cylinderOrCone = tempBRepMgr->createCylinderOrCone(point1, radius1, point2, radius2);

    return cylinderOrCone;
}

Ptr CreateEllipticalCylinderOrCone(double majorRadius1, double minorRadius1, double majorRadius2)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr pointOne = Point3D::create(8.0, 3.0, 0.0);
    Ptr pointTwo = Point3D::create(8.0, -3.0, -3.0);
    Ptr majorAxisDirection = Vector3D::create(1.0, 1.0, 1.0);

    // Create EllipticalCylinder Or Cone
    Ptr ellipicalCylinderOrCone = tempBRepMgr->createEllipticalCylinderOrCone(
        pointOne, majorRadius1, minorRadius1, pointTwo, majorRadius2, majorAxisDirection);
    return ellipicalCylinderOrCone;
}

Ptr CreateSphere(double radius)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr sphereCenter = Point3D::create(0.0, 8.0, 8.0);
    // Create sphere
    Ptr sphere = tempBRepMgr->createSphere(sphereCenter, radius);

    return sphere;
}

Ptr CreateTorus(double majorRadius, double minorRadius)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr axis = Vector3D::create(0.0, 0.0, 10.0);
    Ptr torusCenter = Point3D::create(0.0, 2.0, 8.0);

    // Create torus
    Ptr torus = tempBRepMgr->createTorus(torusCenter, axis, majorRadius, minorRadius);

    return torus;
}

Ptr PlaneIntersection(const Ptr& body)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr planeOrigin = Point3D::create(0.0, 0.0, 0.0);
    Ptr planeNormal = Vector3D::create(0.0, 0.0, 1.0);
    Ptr plane = Plane::create(planeOrigin, planeNormal);

    // creates a brep body by the intersection between the input body and plane
    Ptr intersectionBody = tempBRepMgr->planeIntersection(body, plane);

    return intersectionBody;
}

bool TransformBody(const Ptr& body)
{
    bool isSuccess = false;

    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return isSuccess;

    Ptr transform = Matrix3D::create();
    Ptr translation = Vector3D::create(0.0, 0.0, -5.0);
    isSuccess = transform->translation(translation);
    if (!isSuccess)
        return isSuccess;

    // Transforms the brep body using the specified transformation matrix
    isSuccess = tempBRepMgr->transform(body, transform);
    return isSuccess;
}

Ptr GetWireFromBody(const Ptr& body, size_t index)
{
    Ptr brepWires = body->wires();
    if (!brepWires)
        return nullptr;

    Ptr brepWire = brepWires->item(index);

    return brepWire;
}

bool DeleteFacesOnBody(const Ptr& body, const std::vector& indexes, bool isDeleteSpecifiedFaces)
{
    bool isSuccess = false;

    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return isSuccess;

    Ptr faces = body->faces();
    if (!faces)
        return isSuccess;

    std::vector> brepFaces;
    for each (size_t index in indexes)
    {
        Ptr face = faces->item(index);
        if (!face)
            return isSuccess;

        brepFaces.push_back(face);
    }

    // Delete faces on body
    isSuccess = tempBRepMgr->deleteFaces(brepFaces, isDeleteSpecifiedFaces);
    return isSuccess;
}

Ptr CreateSilhouette(const Ptr& face)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr viewDirection = Vector3D::create(0.0, 0.0, 1.0);

    // Create silhouette body
    Ptr silhouetteBody = tempBRepMgr->createSilhouetteCurves(face, viewDirection, true);

    return silhouetteBody;
}

Ptr CreateWireFromCurves(std::vector>& edgeMap)
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr center = Point3D::create(10.0, 0.0, 5.0);
    Ptr normal = Vector3D::create(0.0, 0.0, 1.0);
    Ptr circle1 = Circle3D::createByCenter(center, normal, 3.0);
    Ptr circle2 = Circle3D::createByCenter(center, normal, 2.0);

    std::vector> curves;
    curves.push_back(circle1);
    curves.push_back(circle2);

    // Create wire from curves
    Ptr wireBody = tempBRepMgr->createWireFromCurves(curves, edgeMap);

    return wireBody;
}

Ptr CreateHelixBody()
{
    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return nullptr;

    Ptr axisPoint = Point3D::create(10.0, 10.0, 10.0);
    Ptr axisVector = Vector3D::create(0.0, 1.0, 0.0);
    Ptr startPoint = Point3D::create(8.0, 2.0, 10.0);
    double pitch = 1.0;
    double turns = 10.0;
    double taperAngle = 0.3;

    // Create helix body
    Ptr helixBody = tempBRepMgr->createHelixWire(axisPoint, axisVector, startPoint, pitch, turns, taperAngle);
    return helixBody;
}

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // Create a new document
    Ptr docs = app->documents();
    if (!docs)
        return false;

    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Set the design is a direct modelling design
    design->designType(adsk::fusion::DirectDesignType);

    // Get the root component of active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get bodies in root component
    Ptr bodies = rootComp->bRepBodies();
    if (!bodies)
        return false;

    // Get TemporaryBRepManager
    Ptr tempBRepMgr = TemporaryBRepManager::get();
    if (!tempBRepMgr)
        return false;

    // Create a temporary solid box
    Ptr box = CreateBox();
    if (!box)
        return false;

    // Check the temporary box property
    bool isTemporary = box->isTemporary();

    // Creates a temporary solid cylinder and cone BRepBody
    Ptr cylinder = CreateCylinderOrCone(3.0, 3.0);
    if (!cylinder)
        return false;

    Ptr cone = CreateCylinderOrCone(2.0, 4.0);
    if (!cone)
        return false;

    // Creates a temporary elliptical solid cylinder and cone BrepBody
    Ptr ellipicalCylinder = CreateEllipticalCylinderOrCone(4.0, 2.0, 4.0);
    if (!ellipicalCylinder)
        return false;

    Ptr ellipicalCone = CreateEllipticalCylinderOrCone(3.0, 2.0, 4.5);
    if (!ellipicalCone)
        return false;

    // Creates a temporary spherical BRepBody
    Ptr sphere = CreateSphere(3.0);
    if (!sphere)
        return false;

    // Creates a temporary toroidal BRepBody
    Ptr torus = CreateTorus(2.0, 1.0);
    if (!torus)
        return false;

    // creates a brep body by the intersection between the input body and plane
    Ptr intersectionBody = PlaneIntersection(box);
    if (!intersectionBody)
        return false;

    // Creates a temporary copy of the input BRepBody
    Ptr copiedBody = tempBRepMgr->copy(intersectionBody);
    if (!copiedBody)
        return false;

    // Transforms the brep body using the specified transformation matrix
    bool isSuccess = TransformBody(copiedBody);
    if (!isSuccess)
        return false;

    // Transforms the brep body using the specified transformation matrix
    isSuccess = TransformBody(copiedBody);
    if (!isSuccess)
        return false;

    // Get brep wires
    Ptr brepWire = GetWireFromBody(intersectionBody, 0);
    if (!brepWire)
        return false;
    Ptr copiedWire = GetWireFromBody(copiedBody, 0);
    if (!copiedWire)
        return false;

    //  Creates a new body by creating a ruled surface between the two input wire bodies.
    Ptr surfaceBody = tempBRepMgr->createRuledSurface(brepWire, copiedWire);
    if (!surfaceBody)
        return false;

    // Performs the specified Boolean operation between the two input bodies
    isSuccess = tempBRepMgr->booleanOperation(cylinder, cone, BooleanTypes::IntersectionBooleanType);
    if (!isSuccess)
        return false;

    isSuccess = tempBRepMgr->booleanOperation(ellipicalCylinder, ellipicalCone, BooleanTypes::UnionBooleanType);
    if (!isSuccess)
        return false;

    // Delete face from a temporary BRepBody
    std::vector indexes;
    indexes.push_back(0);
    indexes.push_back(2);
    isSuccess = DeleteFacesOnBody(ellipicalCylinder, indexes, true);
    if (!isSuccess)
        return false;

    // Calculates the silhouette curve geometry for a given face as viewed from a given direction.
    Ptr faces = torus->faces();
    if (!faces)
        return false;

    Ptr face = faces->item(0);
    if (!face)
        return false;

    Ptr silhouetteBody = CreateSilhouette(face);
    if (!silhouetteBody)
        return false;

    // Create wire from curves
    std::vector> edgeMap;
    Ptr wireBody = CreateWireFromCurves(edgeMap);
    if (!wireBody)
        return false;

    // Creates a body from multiple wires that all lie within the same plane
    std::vector> wireBodies;
    wireBodies.push_back(wireBody);
    Ptr planerBody = tempBRepMgr->createFaceFromPlanarWires(wireBodies);
    if (!planerBody)
        return false;

    // Create helix wire body
    Ptr helixBody = CreateHelixBody();
    if (!helixBody)
        return false;

    // Display the helix edges
    Ptr groups = rootComp->customGraphicsGroups();
    if (!groups)
        return false;

    Ptr group = groups->add();
    if (!group)
        return false;

    Ptr edges = helixBody->edges();

    for each (Ptr edge in edges)
    {
        Ptr curve = edge->geometry();
        if (!curve)
            return false;

        group->addCurve(curve);
    }

    // Add the temprary bodies to direct modeling design, then the temprary bodies will be displayed
    bodies->add(box);
    bodies->add(cylinder);
    bodies->add(cone);
    bodies->add(ellipicalCylinder);
    bodies->add(ellipicalCone);
    bodies->add(sphere);
    bodies->add(torus);
    bodies->add(intersectionBody);
    bodies->add(surfaceBody);
    bodies->add(silhouetteBody);
    bodies->add(planerBody);

    // Exports the input bodies to the specified file.
    std::vector> brepBodies;
    brepBodies.push_back(box);
    brepBodies.push_back(surfaceBody);

    std::string dllPath = getDllPath();
    std::string exportPath = dllPath + "/" + "sampleFile.smt";

    isSuccess = tempBRepMgr->exportToFile(brepBodies, exportPath);
    if (!isSuccess)
        return false;

    // Creates new BRepBody objects based on the contents of the specified file
    std::string filePath = dllPath + "/" + "sampleFile.smt";
    Ptr newBodies = tempBRepMgr->createFromFile(filePath);
    if (!newBodies)
        return false;

    return true;
}

std::string getDllPath()
{
#if defined(_WINDOWS) || defined(_WIN32) || defined(_WIN64)
    HMODULE hModule = NULL;
    if (!GetModuleHandleExA(
            GET_MODULE_HANDLE_EX_FLAG_FROM_ADDRESS | GET_MODULE_HANDLE_EX_FLAG_UNCHANGED_REFCOUNT,
            (LPCSTR)&getDllPath,
            &hModule))
        return "";

    char winTempPath[2048];
    ::GetModuleFileNameA(hModule, winTempPath, 2048);

    std::string strPath = winTempPath;
    size_t stPos = strPath.rfind('\\');
    return strPath.substr(0, stPos);
#else
    Dl_info info;
    dladdr((void*)getDllPath, &info);

    std::string strPath = info.dli_fname;
    int stPos = (int)strPath.rfind('/');
    if (stPos != -1)
        return strPath.substr(0, stPos);
    else
        return "";
    ;
#endif
}
